class TransactionProcessor {
    static let shared = TransactionProcessor()
    private init() {}
    
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    
    func initialize() {
        accounts = DataStore.shared.loadAccounts()
        transactions = DataStore.shared.loadTransactions()
        
        if accounts.isEmpty {
            createSampleAccounts()
        }
    }
    
    private func createSampleAccounts() {
        accounts = [
            Account(accountId: UUID().uuidString,
                   accountNumber: "1234567890",
                   balance: 5000.00,
                   accountType: .checking,
                   currency: "USD"),
            Account(accountId: UUID().uuidString,
                   accountNumber: "0987654321",
                   balance: 10000.00,
                   accountType: .savings,
                   currency: "USD")
        ]
        DataStore.shared.saveAccounts(accounts)
    }
    
    func getAccounts() -> [Account] {
        return accounts
    }
    
    func getAccount(byId accountId: String) -> Account? {
        return accounts.first { $0.accountId == accountId }
    }
    
    func getTransactions(forAccountId accountId: String) -> [Transaction] {
        return transactions.filter { $0.fromAccountId == accountId || $0.toAccountId == accountId }
            .sorted { $0.timestamp > $1.timestamp }
    }
    
    func processTransaction(fromAccountId: String, toAccountId: String?, amount: Decimal, type: Transaction.TransactionType, description: String, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        
        guard amount > 0 else {
            completion(.failure(.invalidAmount))
            return
        }
        
        guard let fromAccountIndex = accounts.firstIndex(where: { $0.accountId == fromAccountId }) else {
            completion(.failure(.accountNotFound))
            return
        }
        
        guard accounts[fromAccountIndex].balance >= amount else {
            completion(.failure(.insufficientFunds))
            return
        }
        
        var transaction = Transaction(
            transactionId: UUID().uuidString,
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            amount: amount,
            type: type,
            timestamp: Date(),
            status: .pending,
            description: description
        )
        
        DispatchQueue.global().asyncAfter(deadline: .now() + 1.0) { [weak self] in
            guard let self = self else { return }
            
            self.accounts[fromAccountIndex].balance -= amount
            
            if let toAccountId = toAccountId,
               let toAccountIndex = self.accounts.firstIndex(where: { $0.accountId == toAccountId }) {
                self.accounts[toAccountIndex].balance += amount
            }
            
            transaction.status = .completed
            self.transactions.append(transaction)
            
            DataStore.shared.saveAccounts(self.accounts)
            DataStore.shared.saveTransactions(self.transactions)
            
            DispatchQueue.main.async {
                completion(.success(transaction))
            }
        }
    }
    
    enum TransactionError: Error {
        case invalidAmount
        case accountNotFound
        case insufficientFunds
        case processingError
        
        var localizedDescription: String {
